import { describe, expect, test } from "bun:test";
import { compileFlowDefinition } from "../../dypai-backend-compiler/src/flowCompiler";
import { db, flow, ref, s } from "./index";

describe("flow branching builder", () => {
  test("guard produces if_else branch and return_response fallback", () => {
    const definition = flow("guard-demo")
      .http({ method: "POST", auth: "public" })
      .input({ amount: s.number() })
      .output({ ok: s.boolean(), error: s.optional(s.string()) })
      .guard(ref.input("amount").gt(0), { ok: false, error: "amount must be positive" })
      .step("charge", db.query({ sql: "SELECT 1 AS ok" }))
      .return({ ok: ref.step("charge", "ok"), error: ref.literal(null) });

    const guardStep = definition.steps.find((step) => step.call === "logic" && step.config.mode === "if_else");
    const fallback = definition.steps.find((step) => step.config.operation === "return_response");
    expect(guardStep).toBeDefined();
    expect(fallback).toBeDefined();
    expect(definition.edges?.some((edge) => edge.when === "false")).toBe(true);
    expect(definition.edges?.some((edge) => edge.when === "true")).toBe(true);

    const compiled = compileFlowDefinition(definition);
    expect(compiled.ok).toBe(true);
    const logicNode = compiled.workflowCode?.nodes.find(
      (node) => node.node_type === "logic" && node.parameters.mode === "if_else",
    );
    expect(logicNode).toBeDefined();
    expect(compiled.workflowCode?.edges.some((edge) => edge.source_handle === "false")).toBe(true);
  });

  test("when produces two handled branches", () => {
    const definition = flow("when-demo")
      .http({ method: "GET", auth: "jwt" })
      .input({ active: s.boolean() })
      .output({ status: s.string() })
      .when(ref.input("active").eq(true))
      .then((branch) => {
        branch.step("yes", db.query({ sql: "SELECT 'yes' AS status" }));
        branch.return({ status: ref.step("yes", "status") });
      })
      .else((branch) => {
        branch.return({ status: ref.literal("no") });
      })
      .end()
      .return({ status: ref.literal("unused") });

    expect(definition.edges?.filter((edge) => edge.when === "true").length).toBe(1);
    expect(definition.edges?.filter((edge) => edge.when === "false").length).toBe(1);
  });

  test("match produces switch handles", () => {
    const definition = flow("match-demo")
      .http({ method: "POST", auth: "jwt" })
      .input({ role: s.string() })
      .output({ message: s.string() })
      .match(ref.input("role"), {
        admin: (branch) => {
          branch.return({ message: ref.literal("admin") });
        },
        default: (branch) => {
          branch.return({ message: ref.literal("denied") });
        },
      })
      .return({ message: ref.literal("unused") });

    const switchStep = definition.steps.find((step) => step.config.mode === "switch");
    expect(switchStep).toBeDefined();
    expect(definition.edges?.some((edge) => edge.case === "case_0")).toBe(true);
    expect(definition.edges?.some((edge) => edge.case === "default")).toBe(true);
  });

  test("linear flow edges stay unchanged without branch groups", () => {
    const linear = flow("linear")
      .http({ method: "GET", auth: "public" })
      .input({ id: s.string() })
      .step("main", db.query({ sql: "SELECT 1 AS ok" }))
      .return({ ok: ref.step("main", "ok") });

    expect(linear.branchGroups).toBeUndefined();
    expect(linear.edges).toEqual([
      { from: "$trigger", to: "main" },
      { from: "main", to: "return" },
    ]);
  });
});

describe("flow branching compile integration", () => {
  test("compileFlowDefinition adapts guarded flow to workflow_code.v2", () => {
    const definition = flow("pay")
      .http({ method: "POST", auth: "public" })
      .input({ amount: s.number() })
      .output({ ok: s.boolean(), error: s.optional(s.string()) })
      .guard(ref.input("amount").gt(0), { ok: false, error: "invalid amount" })
      .step("main", db.query({ sql: "SELECT true AS ok" }))
      .return({ ok: ref.step("main", "ok"), error: ref.literal(null) });

    const compiled = compileFlowDefinition(definition);
    expect(compiled.ok).toBe(true);
    expect(compiled.workflowCode?.nodes.some((node) => node.node_type === "logic")).toBe(true);
  });

  test("compileFlowDefinition adapts code() helper to a javascript_code engine node", () => {
    const builder = flow("compute")
      .http({ method: "POST", auth: "public" })
      .input({ amount: s.number() })
      .output({ total: s.number() });
    const definition = builder
      .step(
        "compute",
        builder.code((ctx) => ({ total: ctx.input.amount * 2 }), { timeoutMs: 8000 }),
      )
      .return({ total: ref.step("compute", "total") });

    const compiled = compileFlowDefinition(definition);
    expect(compiled.ok).toBe(true);

    const jsNode = compiled.workflowCode?.nodes.find((node) => node.id === "compute");
    expect(jsNode?.node_type).toBe("javascript_code");
    expect(typeof jsNode?.parameters.code).toBe("string");
    expect(jsNode?.parameters.code).toContain("async function main({ input, automation, nodes");
    expect(jsNode?.parameters.timeout_ms).toBe(8000);
    expect(jsNode?.parameters.input_data).toEqual({});
    expect(jsNode?.parameters.runtime).toBe("vm");
  });
});
